import { NextResponse } from 'next/server';
import { z } from 'zod';
import { createAdminClient } from '@/lib/supabase/server';
import { requireAdmin } from '../_lib/guard';

export const runtime = 'nodejs';
export const dynamic = 'force-dynamic';

const l10n = z.object({
  en: z.string().trim().max(200).default(''),
  bn: z.string().trim().max(200).default(''),
});

const pkgSchema = z.object({
  id: z.string().trim().max(80).optional(),
  name: l10n,
  price: z.string().trim().max(60).default(''),
  priceNote: l10n,
  duration: l10n,
  badge: l10n,
  featured: z.boolean().default(false),
  highlights: z.array(l10n).max(30).default([]),
});

const schema = z.object({
  hajj: z.array(pkgSchema).max(12),
  umrah: z.array(pkgSchema).max(12),
});

/** Save the public marketing package cards (admin → Website → Packages). */
export async function PATCH(request: Request) {
  const guard = await requireAdmin();
  if (!guard.ok) {
    return NextResponse.json({ ok: false, error: 'Unauthorized' }, { status: guard.status });
  }

  let payload: unknown;
  try {
    payload = await request.json();
  } catch {
    return NextResponse.json({ ok: false, error: 'Invalid request body.' }, { status: 400 });
  }

  const parsed = schema.safeParse(payload);
  if (!parsed.success) {
    return NextResponse.json(
      { ok: false, error: parsed.error.issues[0]?.message ?? 'Please check the package details.' },
      { status: 400 },
    );
  }

  const stamp = Date.now();
  const clean = (arr: z.infer<typeof pkgSchema>[], type: string) =>
    arr
      .filter((p) => p.name.en.trim() || p.name.bn.trim())
      .map((p, i) => ({
        ...p,
        id: p.id || `${type}-${stamp}-${i}`,
        highlights: p.highlights.filter((h) => h.en.trim() || h.bn.trim()),
      }));

  const value = {
    hajj: clean(parsed.data.hajj, 'hajj'),
    umrah: clean(parsed.data.umrah, 'umrah'),
  };

  try {
    const supabase = createAdminClient();
    const { error } = await supabase
      .from('site_settings')
      .upsert({ key: 'packages', value: value as unknown as Record<string, unknown> }, { onConflict: 'key' });
    if (error) {
      console.error('[admin/site-packages] upsert failed:', error.message);
      return NextResponse.json({ ok: false, error: 'Could not save packages.' }, { status: 500 });
    }
    return NextResponse.json({ ok: true });
  } catch (err) {
    console.error('[admin/site-packages] unexpected error:', err);
    return NextResponse.json({ ok: false, error: 'Unexpected error.' }, { status: 500 });
  }
}
